<script setup>
import Circle from '../components/Circle.vue'
import Paragraph from '../components/Paragraph.vue'
import Picture from '../components/Picture.vue'
import { ref, computed, onMounted, onUnmounted } from 'vue'

const activeIndex = ref(null)
const setActive = (index) => {
  activeIndex.value = activeIndex.value === index ? null : index
}

let colors;
colors = {
  1: '#D62A2A', // Даня
  2: '#2A49D6', // Даша М.
  3: '#1AB2EA', // Тимур
  4: '#6C441F', // Даша Д.
  5: '#EA1AC4', // Матвей
  6: '#0BCA3E', // Руслан
  7: '#EAA11A', // Арина
  8: '#A302C4', // Даша Ж.
  9: '#687F12'  // Тёма
};

const desktopCircles = [
  { id: 9, text: "Тёма Рогулин\nПро качество рэпа", top: '21%', left: '65%' },
  { id: 2, text: 'Даша Морозова\nКоварство ассоциаций', top: '8%', left: '6%' },
  { id: 3, text: 'Тимур Чистяков\nРастения в Антарктиде', top: '37%', left: '11%' },
  { id: 4, text: 'Даша Дьячкова\nРеклама, Москва, Лужков', top: '60%', left: '20%' },
  { id: 5, text: 'Матвей Мухорин\nПро ленивцев', top: '14%', left: '37%' },
  { id: 6, text: 'Руслан Степанов\nНастольно-ролевые игры', top: '59%', left: '45%' },
  { id: 7, text: 'Арина Образцова\nНарратив в "Рататуе"', top: '37%', left: '78%' },
  { id: 8, text: 'Даша Жаркова\nРаньше было лучше', top: '63%', left: '67%' },
  { id: 1, text: "Даня Печинкин\nО нейроинтерфейсах", top: '0%', left: '58%' }
].map(circle => ({
  ...circle,
  color: colors[circle.id]
}));

// Альтернативное расположение для мобильной версии (вертикальная ориентация)
const mobileCircles = [
  { id: 9, text: "Тёма Рогулин\nПро качество рэпа", top: '162%', left: '0%' },
  { id: 2, text: 'Даша Морозова\nКоварство ассоциаций', top: '37%', left: '20%' },
  { id: 3, text: 'Тимур Чистяков\nРастения в Антарктиде', top: '-10%', left: '0%' },
  { id: 4, text: 'Даша Дьячкова\nРеклама, Москва, Лужков', top: '208%', left: '55%' },
  { id: 5, text: 'Матвей Мухорин\nПро ленивцев', top: '159%', left: '50%' },
  { id: 6, text: 'Руслан Степанов\nНастольно-ролевые игры', top: '0%', left: '55%' },
  { id: 7, text: 'Арина Образцова\nНарратив в "Рататуе"', top: '55%', left: '60%' },
  { id: 8, text: 'Даша Жаркова\nРаньше было лучше', top: '72%', left: '-8%'  },
  { id: 1, text: "Даня Печинкин\nО нейроинтерфейсах", top: '207%', left: '10%' }
].map(circle => ({
  ...circle,
  color: colors[circle.id]
}));

// Динамическое переключение массива кругов в зависимости от ширины экрана
const isMobile = ref(false)

const updateViewport = () => {
  isMobile.value = window.innerWidth <= 768
}

onMounted(() => {
  updateViewport()
  window.addEventListener('resize', updateViewport)
})

onUnmounted(() => {
  window.removeEventListener('resize', updateViewport)
})

const circles = computed(() => isMobile.value ? mobileCircles : desktopCircles)

</script>

<template>
  <div class="obloga">
    <h1 class="main-title text-h1">ДИДЖ 2</h1>
    <div class="grid-container">
      <!-- Круги -->
      <Circle
          v-for="(circle, index) in circles"
          :key="index"
          :text="circle.text"
          :color="circle.color"
          :position-style="{
          top: circle.top,
          left: circle.left,
          right: circle.right,
          bottom: circle.bottom,
          transform: circle.transform
        }"
          :style="{ opacity: activeIndex === null || activeIndex === index ? 1 : 0.2 }"
          :data-index="index"
          @click="setActive(index)"
      />
    </div>
  </div>
  <div class="content">
    <div id="a2" v-if="activeIndex === 1">
      <Paragraph text="Будни студента-искусствоведа, по большей части, наполнены лекциями, во время которых он находится в аудитории, погруженной в темноту (свет погашен, чтобы не мешать смотреть картинки на проекторе), и слушает преподавателя, рассказывающего об определенном периоде истории искусств. За одну пару мы успеваем посмотреть, в среднем, от 100 до 160 слайдов - умножьте это количество на 10, и получится число картинок, которое студент-искусствовед отсматривает в неделю. Один учебный семестр длится около 20 недель, а значит, количество визуальных образов, обретенных за полгода, увеличивается до трёх тысяч. Такое интенсивное повышение насмотренности дает о себе знать и в повседневной жизни, свободной от стен университета. Визуальные образы коварно поджидают тебя на каждом углу, готовятся всплыть в сознании при малейшей возможности.
Ты можешь столкнуться с ними в метро, когда широкий размах арок на “Волоколамской” напомнит тебе о Святой Софии в Константинополе, про которую тебе читали на втором курсе. Во внутреннем пространстве этой церкви доминирует полусфера купола, в стороны от которой раскрываются, словно лепестки цветка, широко раскинутые арки.
Соседствующие университетскому корпусу дома мерным шагом аркады и круглыми окошками вызовут ассоциации с итальянскими палаццо. Полукруглое окно многоэтажного здания напомнит термальное окно Палладио, который в свою очередь обращался к образу римских терм.
Подобные ассоциации возникают неожиданно и невольно: например, когда ты выходишь из кабинета и видишь план корпуса, и он напоминает тебе планы замков, которые ты смотрел на протяжении последних полутора часов.
Особенно бурно бурлит этот вихрь из образов во время подготовки к экзаменам, когда ты пытаешься запомнить все три тысячи картинок. Так, после многочасового просмотра византийских мозаик мне чудились осколки стеклышек-тессер в очертаниях лиц реальных людей.
Каждый из описанных мной примеров - не выдумка в угоду текста. Было любопытно собрать эти случаи вместе и подумать о том, как то, чему мы посвящаем большое количество времени, влияет на наше восприятие окружающего мира. Интересно также подумать о том, насколько случайны эти ассоциации. Между станцией метро, открытой в 2009 году, и всемирно известным собором юстиниановской эпохи, казалось бы, не может быть ничего общего. Однако их объединяет сама форма арки, разработанная еще в Древнем Риме. То же самое произошло и со многими другими элементами архитектуры - со времен античности через многократные ренессансы и многочисленные памятники они добрались до нас, став частью нашей обыденности. А мне удалось их вычислить. Или всё же просто показалось."/>
      <Picture
          src="pics/1_dasha_m_1.png"
          alt="Картинка Даши М."
      />
    </div>
    <div id="a1" v-if="activeIndex === 8">
      <Paragraph text="Вот идёте вы по тротуару и видите человека, а он какой-то весёлый (вы как-то распознали эту эмоцию), и тут до вас доходит, что это ваш приятель: например, Боря (вы это поняли, покопавшись в своей памяти, нащупав визуальную схожесть и вспомнив имя в паре с его очаровательной улыбкой). Дело обычное - решаете поздороваться. Обычно говорите ему: “Здарова, Борь!” или жмёте руку. Приняв решение (опять головой!), пускаете сигнал нужному органу: либо руке, которая потянется вверх, либо же рту, который издаст звуки (как речь работает - пока понятия не имею).
Почти во всех действиях, где мы взаимодействуем с внешним миром, между идеей (в голове) и её осуществлением есть посредник - какая-то часть нашего тела (любое действие: подмигивание, прыжок в баскетболе, покручивание бёдрами). В двадцатом веке учёные серьёзно задумались, как можно этого посредника упустить (цели обсудим попозже) или заменить. И к сегодняшнему дню пришли к значительным результатам: дело в том, что разные части мозга отвечают за разные вещи. То есть известно, где:
- хранится информация о том, что мы знакомы в Борисом;
- принимается решение, пожать руку и выкрикнуть “привет”;
- рождается намерение согнуть руку в локте.
Если получится узнать, что мы намереваемся пожать руку, а на деле рука (тьфу-тьфу-тьфу) ампутирована, то ситуацию можно изменить с помощью робо-руки, например. Разберём процесс по шагам. Мы решили, что собираемся согнуть левую руку в локте. Часть мозга, отвечающая за движения, начинает активно работать, то есть нейроны (которых у нас в голове огромное количество) начинают между собой общаться: передавать сигналы (либо химически, либо электрически - нам интереснее это, потому что движение тока между нейронами создаёт магнитное поле). Этот сигнал мы уже можем считать. Существуют разные методы: инвазивные и неинвазивные. Отличие в том, нужно ли хирургическое вмешательство, чтобы установить считывающее устройство. В случае инвазивных методов устройство помещается на поверхность мозга или прямо в него - то есть, нужно хирургическое вмешательство. В неинвазивных же никакого вмешательства не требуется: мы будем считывать сигналы с поверхности черепа, даже бриться не придётся. Понятное дело, что точность сигналов падает, но зато так намного дешевле и безопаснее. И часто этого вполне достаточно. Тут устройство (для EEG) похоже на плавательную шапочку, из которой выходит много проводов, которые как раз получают значения напряжения с разных частей мозга.
Итак, мы каким-то образом считываем сигналы и, предобрабатывая их (сюда входит очистка от шумов, выделение признаков и другие важные механизмы), получаем данные об уровне активности в разных частях мозга. Тут в ход вступает машинное обучение. Мы ищем паттерны (повторяющиеся действия со своими особенностями), учимся выявлять, что определённый всплеск характеризует наше желание поднять левую руку. Обучившись связывать конкретное изменение сигналов с конкретным действием, мы можем передавать команду робо-руке поднять её в определённое положение.
А, название-то не сказал: всё это можно назвать нейроинтерфейсами (на английском - brain-computer interface). Использоваться может для разных вещей совершенно.Помогает восстановиться после инсульта (даже если повреждена часть мозга, отвечающая непосредственно за действие, мы можем извлекать информацию из области по соседству той, которая отвечает за намерение сделать действие) или справиться с другими трудностями, например: расстройствами сна или эпилепсией. Если после травмы какой-то конечности не стало или она парализована (со стороны мышц), то можно с помощью экзо-скелетов или других специальных устройств вернуть возможность двигаться (не полностью самостоятельно, но и это уже бесценно - я смотрел видео о существующих сегодня технологиях и видел растрогавшуюся женщину, почти полностью парализованную, которой впервые за 15 лет удалось попить без помощи других людей). Можно и просто творить силой мысли, играть в игры, работать в профессиональных программах и писать со скоростью, не уступающей скорости на бумаге (можете попробовать эксперимент: сколько букв вы можете написать за минуту, если около ста - у вас ничья).
Сегодня существует немало стартапов, создающих нейроинтерфейсы, расскажу про несколько из них. Самый популярный - Neurolink (та самая компания Илона Маска), внедряют в мозг чипы, с помощью которых можно управлять своим компьютером (из того, что видел: проектировать 3D-объекты и играть в CS:GO) и узнавать что-то новое про себя в мобильном приложении, но для этого нужно внедрить себе в мозг имплант, что сделали уже два человека (информация на декабрь 2024, опираясь на блог компании). Конечно, все разработки делаются в первую очередь для людей с физическими ограничениями или болезнями, которые к этим ограничениям привели. Другой пример - Synchron Stentrode, помогают парализованным людям, но хирургическое вмешательство на черепе уже не требуется: электрод - он представляет из себя тонкий провод с сеточкой на конце - заводят через вену в районе ключицы. Он с кровью доставляется в мозг, со временем врастает в стенку мозга и передает сигналы к устройству, которое подключается в районе ключницы. Звучит, конечно, жутковато, но на картинках - очень даже аккуратно. Есть и много неинвазивных устройств и стартапов - в учебных и исследовательских целях пользуются в основном ими. Из стартапов мне запомнился Neurable. Недавно (2021) они выпустили наушники, которые анализируют взаимосвязь концентрации и разных музыкальных жанров, таким образом наушники могут помочь собраться с мыслями в нужный момент. Наш мозг устроен очень запутанно, и познавать его механизмы очень интересно. Просто задумайтесь, что мозгом мы пытаемся понять, как работает... наш мозг. Наверно, я полностью никогда и не пойму, как оно всё там работает. Ну и ничего, просто говорю себе / ему спасибо и иду дальше радоваться жизни.

Источники:
Курс лекций по BCI, Aberham Genetu Feleke
https://habr.com/ru/articles/431574/
https://neuralink.com/"/>
    </div>
    <div id="a6" v-if="activeIndex === 5">
      <Paragraph text="В последние несколько лет настольно-ролевые игры переживают очередной расцвет своей популярности. Настольно-ролевые игры - это жанр настольных игр, в котором участники устно описывают действия своих персонажей, опираясь на их особенности, и где успех действий зависит от игровой системы. Первой коммерческой настольной ролевой игрой была Dungeons and dragons, вышедшая в 1974 году. Этот феномен часто упоминается в кинематографе, например в “Теории большого взрыва”. С 2022-го года выходит аниме по мотивом одной из игр с канала Critical Role: “Легенда о Vox Machina” и насчитывает уже целых три сезона, а вскоре обещают выпустить ещё и четвёртый. В 2023-м году вышел целый полнометражный фильм “Подземелья и драконы: Честь среди воров”. Если приводить примеры из русскоязычного сегмента, то на YouTube регулярно выходят выпуски шоу “Подземелья Чикен Карри, с различными известными людьми, к тому же набирающие по миллиону или более просмотров каждый. И, хоть лично я не фанат последнего, поскольку это шоу больше юмористическое, но тем не менее, оно значительно повышает популярность этого формата развлечений. Так что, не особо удивительно, что в сообществе НРИ можно встретить совершенно разных людей, как по характеру, так и области деятельности в жизни.
С психологической точки зрения НРИ, как и компьютерные, являются средством эскапизма, то есть способом побега от реальности и рутины. Идея написания этой статьи пришла мне в голову, когда мы планировали начать новую кампанию и с одним моим другом создали почти тех же самых персонажей, что и в прошлый раз. То есть это, конечно, были другие персонажи, с другими именами, внешностью, предысторией и даже существовали они в совершенно ином мире, но по сути своей их характеры, методы достижения целей и их мотивация были такими же, только в слегка другой обёртке. После обсуждений мы пришли к выводу, что в целом почти у каждого игрока в НРИ существуют определённые шаблоны, по которым он создаёт своего персонажа.
Например, человек отыгрывает персонажа, изучающего незнакомый самому игроку мир, погружаясь в него с головой, выискивая новую информацию, замещая свою обыденную и зачастую не самую интересную жизнь иной, полной магии, жизни в мире киберпанка или поиске страниц книги Нод. Условно, можно обозначить этот типаж персонажа как исследователя. Чаще всего, таких персонажей создают люди, в жизни не так много ярких и запоминающихся моментов. Таким образом, они пытаются создать себе более интересную реальность.
Другой пример, это игроки, выбирающие агрессивных персонажей, методы которых не всегда оправданы. Они часто переступают нормы закона и морали, создавая проблемы другим персонажам. В связи с чем, родилось ироничное название такого типа “бомжи-убийцы”, которые творят хаос и насилие, ради развлечения. Людям, выбирающим этот типаж интересно узнать, каково это преступить черту закона, поскольку в жизни большинство людей стараются жить в рамках, ведь знают, что нарушение закона влечёт за собой наказание.
Третий типаж, в том числе и мой самый любимый, манипулятор. Он предстаёт в разных амплуа: магов с божественными силами, столетних вампиров, имеющих тонны влияния и связей или просто заносчивых аристократов, считающих людей вокруг недостойными. В основе этого паттерна в первую очередь лежит желание контроля над ситуацией, ведь многим людям порой хочется почувствовать себя сильными мира сего, решать проблемы по щелчку пальцев или не быть ни коим образом зависимым от чужих решений. Это относительно сложный в освоении базис персонажа, но при этом приносящий огромное удовольствие от игры им, поскольку власть, сосредоточенная в твоих руках, опьяняет.
Следующий популярный типаж - роль ребёнка, которую частенько примеряют на себя инфантильные взрослые, имевшие в детстве крайне строгих родителей и так и не ощутившие себя в полной мере ребёнком в своём детстве. У них были гиперопекающие родители, которые принимали за них ключевые жизненные решения. Поэтому они ещё раз хотят пройти путь взросления, но в этот раз решая самостоятельно.
Крайне часто, люди вносят в своих персонажей возможность выстроить их собственную реальную жизнь по идеальному сценарию, как например возможность построить хорошие отношения с родителями, которые не понимают человека совершенно. Или же желание заботиться о дорогом человеке, которое в реальной жизни уже почти неосуществимо, в связи со смертью, расстоянием или же иными причинами.
Некоторые игроки прописывают своих персонажей сорвиголовами, которые влезают во все разборки и социальные взаимодействия, стараясь активно навязать своё мнение. В обыденной жизни такие люди являются достаточно замкнутыми и спокойными, им сложно находить общий язык с другими людьми, поэтому в игре они отчаянно хотят быть услышанными, зачастую, привлекая к себе внимание не лучшими способами.
Эта статья не является, каким бы то ни было серьёзным психологическим исследованием и не описывает совершенно всех игроков в настолько-ролевые игры. Однако, резюмируя всё вышесказанное, я советую Вам попробовать НРИ, это крайне интересное времяпрепровождение, которое в какой-то мере помогает узнать самого себя, прокачать совершенно разные полезные в жизни навыки, а также завести новые знакомства. Ну, а если вы уже играете в подобные развлечения, то возможно стоит повнимательнее присмотреться к вашим сопартийцам, быть может их персонаж рассказывает о них самих гораздо больше, чем они при личной беседе."/>
    </div>
    <div id="a7" v-if="activeIndex === 6">
      <Paragraph text="Кто нарратор? Вы замечали, что в мультфильме «Рататуй» довольно сложная структура повествования несмотря на то, что основные сюжетные события происходят хронологически, мотивируются предыдущими и вытекают из друг друга. Мы, как зрители, легко можем воспринимать это повествование, поскольку оно для нас представлено как одно целое. Однако, почему в некоторых моментах получаются разные точки кульминации или по времени не состыковываются сюжетные препятствия героев? В «Рататуе» применяется форма повествования от первого лица с вкраплениями линий других персонажей, эпизоды которых рассказаны зрителям, но при этом неизвестны повествователю. Чтобы ответить на вопрос, предлагаю провести нарративный анализ данного кинотекста (в оригинале). Конкретный интерес составляет не полное анализирование нарратива, а рассмотрение позиции нарратора — повествователя истории, того, чьими глазами зритель воспринимает происходящие на экране события.
Как я уже обозначила, события повествуются от первого лица, значит нарратор должен быть главным героем истории. В тексте “Рататуя” таким персонажем является Реми по следующим причинам:
1. Вокруг него строится повествование. За экраном остается то, что произошло с родной колонией крыс Реми, как они выжили и нашли новое место для жизни; или как продолжалось и закончилось свидание Колетт и Лингвини, которые уехали на мотоцикле, случайно уронив Реми на проезжую часть. Продолжения всех этих эпизод без участия Реми мы не знаем.
2. Сетка персонажей вырисовывается через призму восприятия этих персонажей самим Реми. Для нас шеф Гюсто идейный вдохновитель и настоящий творец, только потому что таким его воспринимал Реми. Для шеф-поваров ресторана Гюсто, кроме Колетт, он не был таким же безупречным кумиром, поскольку они не принимали того факта, что Реми – гениальный повар, а значит и не верили главному лозунгу Гюсто: “Anyone can cook”. Рост и перемены персонажей также происходят на фоне эволюции их взаимоотношений с главным героем, например, Лингвини перестает лгать, чтобы защитить Реми, Эго меняет свои принципы и взгляды на творцов и творение только тогда, когда пробует приготовленное Реми блюдо. В то время как у главного героя – только во взаимоотношениях с самим собой. Диалоги с воображаемым Гюсто являются лишь визуализацией внутреннего конфликта Реми.
3. Рассмотрение и решение поднимаемых проблем. В вечной борьбе двух ипостась – творца и критика, в конце данной истории побеждает творец, так как главный идеологический тезис “Anyone can cook” соответствует или правильнее сказать формирует мировоззрение главного героя.

Таким образом, Реми, как главный герой, единственный может быть рассмотрен в качестве нарратора в кинотексте, но все ли так просто?

С первых минут просмотра зритель знакомится с закадровым комментатором, использующий на протяжении всего текста “я-нарратив” в отношении героя Реми и повествовательные конструкции в прошедшем времени. Это также характеризует его как повествователя или нарратора, одновременно участвующего в происходящих событиях и рассказывающего их. Он достоверно неизвестен внешними чертами зрителю и своим именем, так как несмотря на то, что первыми же репликами он идентифицировал себя с вылетающим из окна Реми («This is me. I think it’s apparent I need to rethink my life a little bit»), он может быть не эквивалентен с главным героем. Есть следующие причины, из-за которых мы вероятно сразу “поверим” в то, что они одно целое:
1. Одинаковое озвучивание: оба говорят голосом одного актера озвучки, на английском языке без французского акцента, в отличие от других персонажей.
2. Комментатор озвучивает только мысли персонажа Реми (за исключением монолога Эго в конце, но в этом случае мы слышим
не мысли, а написанную статью, не находящуюся в закрытом доступе – в сознании). Соответственно он имеет доступ только к сознанию главного героя. Это можно проследить на эпизодах знакомства зрителя в самом начале с главным героем, его братом и отцом, диалога Реми с выдуманным им образом Гюсто и фантазирования крысенка над красками и вкусовыми ощущениями от еды, поскольку мы находимся в воображаемом мире героя, где действительность меняется на явно нарисованный фон.
3. Комментатор использует “я-нарратив” только в отношении персонажа Реми.
4. Идеологически и оценочно одинаково видят реальность.
5. Также можно обратиться к концу текста и заметить, что комментатор, продолжая свои реплики, раскрывается как персонаж Реми, рассказывающий историю своего пути в кулинарию другим крысам за столом. То есть весь сюжет был построен как “рассказ” Реми.
Как написано в последнем пункте, мы узнаем внешность и личность нарратора в конце истории, которая действительно идентична персонажу Реми. Тогда мы можем предположить, что закадровый комментатор – не самостоятельный нарратор, а эксплицитный способ изображения нарратора Реми в повествовании, а его деятельность внутри повествования изображается имплицитно. У нарратора есть повествующее “я” – закадровый голос с “я-нарративом” и повествуемое “я” – персонаж в сюжете. Таким образом, Реми можно протипировать как диегетического нарратора-протагониста, которым он остается на протяжении всего повествования.

Противоречия возникают в фокализации. Разделим историю на три части:
Первая: Экспозиция-знакомство с персонажем в начале сюжета, где активно присутствует закадровый голос и ощущение субъективной выжимки важной о нем информации (сменяющиеся эпизоды из жизни Реми, он рассказывает о своем даре развитого нюха, о конфликте между ним и отцом, о его принципах, н-р, «if you are what you eat, then I only want to it the good staff», и тяге к человеческому обществу и их способности создавать – до момента его решения подняться наверх из канализации, где остался совсем один). Фокализация здесь внутренняя, поскольку нарратор=персонажу, они оба знают одинаковое количество информации.
Вторая: Все основные повествовательные события, в которых закадровый голос фигурирует всего дважды и только с целью воспроизведения мыслей персонажа Реми. В этой части сюжета определенно много эпизодов рассказанных тем же нарратором, что и в первой. Много темпорально субъективных эпизодов, которые протекают заметно быстрее, чем они могли в объективной реальности: эпизоды, где Реми исправляет испорченный Лингвини суп или готовит вместе с Лингвини успешный “Special order”, а также тренировки с Колетт. Эпизоды, в которых наоборот время растягивается, например, побег с кухни, который предпринимает Реми. Этот эпизод в целом достаточно субъективен, благодаря кинематографической специфики повествования (Камера снимает происходящее на уровне Реми, показывая «его рамки видимого» и используется субъективная съемка снизу вверх, а также звуковое сопровождение, характеризующее переменчивый накал и динамику состояния Реми).
Однако в этой части сюжета не сходится Реми персонаж – повествуемое “я” и Реми нарратор – повествующего “я”.
Фокализация меняется на нулевую, нарратор начинает знать больше, чем персонаж, поскольку появляются эпизоды, в которых не участвует главный герой и которые изображают другую точку зрения на происходящее и на героя. Например, нарратор открывает зрителю эпизоды с участием антагониста шефа Скиннера, важную информацию из которых главный герой узнает сам, уже в эпизодах от его лица. Скиннер прочитал письмо от матери Лингвини раньше, зритель узнал о том, что юноша сын Гюсто раньше, а Реми узнал об этом сам из записки спустя время. Примером другой точки зрения на персонажа являются эпизоды, в которых нарратор меняется на персонажа человека и основным их маркером является смена коммуникации Реми с персонажами с понятного нам человеческого языка на невербальное общение или просто издаваемый Реми “крысиный писк”. Зритель переключается на объективную для него реальность, где животные не способны результативно коммуницировать с людьми. Такие кадры были в начале от лица старухи, которая стреляла в Реми и Эмиля, от лица Лингвини на протяжение всей истории (н-р, на пресс-конференции Лингвини).
Третья: Возвращение закадрового голоса в конце произведения (в эпизоде, когда Эго узнает, что шеф-поваром был Реми) и такого же нарратора как в части 1. История завершается в конце рассказа персонажа Реми, именно в последнем эпизоде закадровая речь сливается с речью персонажа. Здесь выделяется только смена принадлежности закадрового голоса от Реми к Эго, и зритель слышит, написанную статью критика. Этот прием скорее связан не со сменой нарратора, а со способом передачи финальной идейной речи, которая проходит через сознание всех персонажей (закадровая речь Эго сопровождает визуальный ряд со всеми основными персонажами, которые в ночной час задумчиво лежат перед сном).

Эти три части, поделенные относительно присутствия закадрового нарратора Реми, раскрывают противоречивость в определении нарратора как диегетического нарратора-протагониста. С одной стороны, нарратор явно существует как повествующий, потому что повествуемый мир зритель видит через призму главного героя, но он не существует как повествуемый во всем сюжете, поскольку есть рассказанные эпизоды с другой объективной оценкой происходящего или линией нарратора-человека, которые не доступны персонажу. С другой стороны, в конце повествования нам явно раскрывают нарратора как персонажа Реми, но по каким причинам он может быть нарратором, если ему неизвестны часть эпизодов из нарративного повествования?

Литература:
Шмид В. Нарратология//, – М.: Языки славянской культуры, 2003. – 63-96 с., 112-115 с."/>
